-- Migration: Seed issues batch 4 (issues 13-15)

INSERT INTO issues (rank, slug, icon, severity, title, anchor_stat, short_desc, definition, australian_data, mechanisms, impacts, groups, sources) VALUES
(13, 'racism-discrimination', '🤜', 'high',
 'Racism, Discrimination & Exclusion',
 'Mission Australia Youth Survey 2024: discrimination and inequality rated a top societal concern by Australian youth',
 'Racism in Australian schools is not just a social justice issue — it is a documented mental health and educational attainment crisis. Children who experience discrimination learn less and suffer more.',
 'Racism and discrimination in schools includes direct incidents (slurs, exclusion, physical aggression based on race), structural racism (curriculum that excludes non-Western cultures), and microaggressions (everyday dismissals and othering). All forms cause documented psychological harm.',
 'Mission Australia Youth Survey 2024 identifies discrimination and inequality as a top-ranked societal concern among young Australians. eSafety Commissioner data documents that online hate — frequently racialised — is encountered by a significant proportion of young people. Aboriginal students, students from refugee backgrounds, and Muslim students are among the most frequently targeted groups.',
 'Repeated exposure to discrimination activates a chronic stress response. Identity-based attacks threaten the self-concept at a developmentally critical time. Racial discrimination in schools has been shown to reduce academic self-efficacy, reduce help-seeking behaviour, and increase disengagement and absence.',
 '[{"title":"Academic Identity","text":"Discrimination directly reduces students'' belief in their own academic capability and belonging."},{"title":"Mental Health","text":"Racial trauma is associated with elevated anxiety, depression, and PTSD symptoms in young people."},{"title":"Attendance","text":"Students who experience discrimination regularly avoid school to avoid continued exposure."},{"title":"Institutional Trust","text":"Schools that tolerate discrimination lose the trust of entire family communities, not just individual students."}]'::jsonb,
 '["Aboriginal & Torres Strait Islander students","Students of African background","Muslim students","Students from refugee and asylum seeker families","East and South Asian students"]'::jsonb,
 '["Mission Australia Youth Survey 2024","eSafety Commissioner Online Hate Research","AIHW Social Determinants and Child Health"]'::jsonb),

(14, 'motivation-disengagement', '🎯', 'notable',
 'Motivation & Learning Disengagement',
 'RoGS 2026 defines cognitive engagement including motivation as a key schooling indicator, measured across jurisdictions',
 'Motivation is not a personal failing — it is the product of whether a student believes school is relevant, safe, and achievable. When schools lose student motivation, they lose the students.',
 'Learning engagement encompasses cognitive (motivation), behavioural (attendance, participation), and emotional (belonging, interest) dimensions. The Productivity Commission''s RoGS framework uses all three. Motivation refers to the drive to engage with learning — both intrinsic and extrinsic.',
 'RoGS 2026 defines engagement dimensions and notes that jurisdictions collect engagement data through student surveys. Mission Australia Youth Survey 2024 identifies motivation as a barrier to personal goals for many young Australians. Attendance data shows progressive secondary school disengagement, with Year 9–10 seeing the steepest national drops.',
 'Motivation requires perceived competence (''I can do this''), perceived value (''This matters''), and psychological safety (''I won''t be humiliated if I try''). Wellbeing deficits undermine all three. Anxiety says ''you might fail''. Discrimination says ''this isn''t for you''. Bullying makes classroom participation dangerous.',
 '[{"title":"Learning Depth","text":"Unmotivated students learn shallowly — retaining less, applying little, and progressing slowly."},{"title":"Attendance","text":"Low motivation is a primary driver of voluntary disengagement and increasing absenteeism."},{"title":"Teacher Relationships","text":"Disengaged students are harder to reach — creating frustration cycles in classrooms."},{"title":"Future Aspiration","text":"Low school motivation correlates with lower post-school aspiration and workforce participation."}]'::jsonb,
 '["Students in outer regional and remote areas","Aboriginal & Torres Strait Islander students","Boys in secondary school (engagement gap)","Students who have experienced bullying","Students with undiagnosed learning difficulties"]'::jsonb,
 '["Productivity Commission RoGS 2026 — School Education Engagement","Mission Australia Youth Survey 2024","ACER PISA 2022 — Motivation indicators"]'::jsonb),

(15, 'reporting-gaps', '⚠️', 'notable',
 'Safety & Wellbeing Incident Reporting Gaps',
 'Queensland Auditor-General Report 6 (2024–25): Australia''s only state-level public accountability dataset on school safety incidents',
 'How schools record and report wellbeing incidents varies dramatically across jurisdictions. Queensland''s audit exposes what happens when accountability is taken seriously — and what the silence elsewhere reveals.',
 'Safety and wellbeing incidents encompass bullying, harassment, discrimination, physical assault, and self-harm episodes requiring school intervention. How consistently they are recorded determines whether patterns can be identified and addressed.',
 'The Queensland Auditor-General''s Report 6 (2024–25) represents Australia''s most comprehensive accountability snapshot on school safety incidents, recording over 46,000 events in Queensland state schools in 2023. Other jurisdictions have no equivalent public dataset, making national comparison impossible.',
 'Consistent incident reporting is a precondition for evidence-based safety interventions. Without data, patterns cannot be identified, resources cannot be targeted, and schools cannot be held accountable. The absence of national standards means an identical incident is handled and recorded very differently across Australia''s eight jurisdictions.',
 '[{"title":"Accountability","text":"Without data, schools cannot be held accountable for student safety outcomes by governments or parents."},{"title":"Resource Allocation","text":"Data gaps mean welfare resources cannot be effectively targeted to schools with the highest need."},{"title":"Parent Trust","text":"Inconsistent reporting erodes parent confidence in school safety systems and transparency."},{"title":"Policy Development","text":"National wellbeing policy cannot be evidence-based without consistent national incident data."}]'::jsonb,
 '["Students in jurisdictions without public reporting","Aboriginal & Torres Strait Islander students (underreported incidents)","LGBTQ+ students","Students in non-government schools","Remote school students"]'::jsonb,
 '["Queensland Auditor-General Report 6 (2024–25) — Protecting Students from Bullying","Department of Education Anti-Bullying Rapid Review Consultation Paper","AIHW — Australia''s Children Data Gaps Notes"]'::jsonb);
